  `Avatar` text COLLATE utf8mb4_unicode_ci,
  `IdCongTy` text COLLATE utf8mb4_unicode_ci,
  `DiaChiLamViec` text COLLATE utf8mb4_unicode_ci,
  `HinhThucLamViec` text COLLATE utf8mb4_unicode_ci,
  `GioLamViec` text COLLATE utf8mb4_unicode_ci,
  `MuiGio` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
